export interface Source {
  id: string;
  name: string;
  content: string;
}

export type ActiveView = 'source' | 'plan' | 'flashcards' | 'quiz' | 'search';

export type UserTier = 'free' | 'premium';

export type TrustedSource = 'Britannica' | 'Khan Academy' | 'Wikipedia';

export type ExamBoard = 'AQA' | 'OCR' | 'Edexcel';

export interface RevisionPlanItem {
  topic: string;
  subtopics: string[];
}

export type RevisionPlan = RevisionPlanItem[];

export interface Flashcard {
  term: string;
  definition: string;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: string;
}

export interface GroundingSource {
  uri: string;
  title: string;
}

export interface AiSearchResult {
  summary: string;
  sources: GroundingSource[];
}

export interface SearchStatus {
  count: number;
  lastDate: string;
}

import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, AiSearchResult, ExamBoard, SearchStatus } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';

const MAX_FREE_SEARCHES = 15;

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchResult, setSearchResult] = useState<AiSearchResult | null>(null);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);

  const [searchStatus, setSearchStatus] = useState<SearchStatus>(() => {
    const saved = localStorage.getItem('search-status');
    const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
    if (saved) {
      const parsed = JSON.parse(saved) as SearchStatus;
      if (parsed.lastDate === today) return parsed;
    }
    return { count: 0, lastDate: today };
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  useEffect(() => {
    localStorage.setItem('search-status', JSON.stringify(searchStatus));
  }, [searchStatus]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleDeleteSource = (sourceId: string) => {
    if (selectedSource?.id === sourceId) {
      setSelectedSource(sampleSources[0] || null);
      setActiveView('source');
    }
    setSources(prevSources => prevSources.filter(source => source.id !== sourceId));
  };


  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    setSearchResult(null);
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    const today = new Date().toLocaleDateString('en-CA');

    // Check limit for free tier
    if (userTier === 'free') {
      if (searchStatus.lastDate === today && searchStatus.count >= MAX_FREE_SEARCHES) {
        setShowTierModal(true);
        return;
      }
    }

    setIsLoading(true);
    setLoadingMessage('Searching the web...');
    setSearchResult(null);
    try {
      const result = await searchWithAi(query, trustedSources, examBoards);
      setSearchResult(result);

      // Only increment for free users
      if (userTier === 'free') {
        setSearchStatus(prev => ({
          count: prev.lastDate === today ? prev.count + 1 : 1,
          lastDate: today
        }));
      }
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      alert("Sorry, I couldn't complete the search. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [userTier, searchStatus]);

  const renderMainContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchResult={searchResult} userTier={userTier} searchCount={searchStatus.count} maxSearches={MAX_FREE_SEARCHES} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} /> : null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans">
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        onDeleteSource={handleDeleteSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        toggleTheme={toggleTheme}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
        searchCount={searchStatus.count}
        maxSearches={MAX_FREE_SEARCHES}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} />
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { AiSearchResult, TrustedSource, ExamBoard, UserTier } from '../types';

interface AiSearchProps {
  onSearch: (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => void;
  searchResult: AiSearchResult | null;
  userTier: UserTier;
  searchCount: number;
  maxSearches: number;
}

const sourceOptions: TrustedSource[] = ['Britannica', 'Khan Academy', 'Wikipedia'];
const examBoardOptions: ExamBoard[] = ['AQA', 'OCR', 'Edexcel'];

export default function AiSearch({ onSearch, searchResult, userTier, searchCount, maxSearches }: AiSearchProps) {
  const [query, setQuery] = useState('');
  const [selectedSources, setSelectedSources] = useState<TrustedSource[]>([]);
  const [selectedExamBoards, setSelectedExamBoards] = useState<ExamBoard[]>([]);

  const handleSourceToggle = (source: TrustedSource) => {
    setSelectedSources(prev => 
      prev.includes(source) 
        ? prev.filter(s => s !== source)
        : [...prev, source]
    );
  };

  const handleExamBoardToggle = (board: ExamBoard) => {
    setSelectedExamBoards(prev =>
      prev.includes(board)
        ? prev.filter(b => b !== board)
        : [...prev, board]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      onSearch(query.trim(), selectedSources, selectedExamBoards);
    }
  };

  const remaining = Math.max(0, maxSearches - searchCount);
  const isLimited = userTier === 'free';

  return (
    <div className="flex flex-col h-full w-full max-w-4xl mx-auto px-4">
      <div className="pt-8 pb-6">
        <div className="flex flex-col items-center mb-2">
            <h2 className="text-3xl font-bold text-gray-900 dark:text-white text-center">AI Search Engine</h2>
            {isLimited && (
                <div className="mt-2 flex items-center bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-full">
                    <div className="w-2 h-2 bg-indigo-500 rounded-full mr-2 animate-pulse"></div>
                    <span className="text-xs font-semibold text-indigo-600 dark:text-indigo-300">
                        {remaining} free searches remaining today
                    </span>
                </div>
            )}
        </div>
        <p className="text-gray-500 dark:text-gray-400 text-center">Find explanations for complex topics, backed by web sources.</p>
        <form onSubmit={handleSubmit} className="mt-6">
          <div className="flex shadow-sm">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="e.g., Explain the theory of relativity"
              className="w-full bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white rounded-l-lg p-4 text-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-transparent dark:border-gray-600"
            />
            <button type="submit" className="bg-indigo-600 text-white px-8 rounded-r-lg font-semibold hover:bg-indigo-700 transition-colors">
              Search
            </button>
          </div>
          <div className="mt-4 flex flex-col lg:flex-row items-center justify-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Sources:</span>
              <div className="flex gap-1">
                {sourceOptions.map(source => (
                    <button
                    key={source}
                    type="button"
                    onClick={() => handleSourceToggle(source)}
                    className={`px-3 py-1 text-xs rounded-full transition-all duration-200 ${
                        selectedSources.includes(source)
                        ? 'bg-indigo-600 text-white shadow-md'
                        : 'bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
                    }`}
                    >
                    {source}
                    </button>
                ))}
              </div>
            </div>
            <div className="hidden lg:block w-px h-4 bg-gray-300 dark:bg-gray-600"></div>
            <div className="flex items-center gap-2">
               <span className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Boards:</span>
               <div className="flex gap-1">
                {examBoardOptions.map(board => (
                    <button
                    key={board}
                    type="button"
                    onClick={() => handleExamBoardToggle(board)}
                    className={`px-3 py-1 text-xs rounded-full transition-all duration-200 ${
                        selectedExamBoards.includes(board)
                        ? 'bg-indigo-600 text-white shadow-md'
                        : 'bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
                    }`}
                    >
                    {board}
                    </button>
                ))}
               </div>
            </div>
          </div>
        </form>
      </div>
      <div className="flex-grow overflow-y-auto">
        {searchResult ? (
          <div className="animate-fade-in space-y-6 pb-8">
            <div className="prose prose-lg prose-gray dark:prose-invert max-w-none text-gray-700 dark:text-gray-300 leading-relaxed">
              <p>{searchResult.summary}</p>
            </div>
            {searchResult.sources.length > 0 && (
              <div>
                <h3 className="text-lg font-semibold text-gray-600 dark:text-gray-400 mb-3 flex items-center">
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.826L10.242 9.172a4 4 0 015.656 0l4 4a4 4 0 01-5.656 5.656l-1.102 1.101" /></svg>
                    Verification Sources
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {searchResult.sources.map((source, index) => (
                    <a
                      key={index}
                      href={source.uri}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block p-4 bg-gray-100 dark:bg-gray-700 rounded-xl border border-transparent hover:border-indigo-400 dark:hover:border-indigo-500 transition-all hover:shadow-lg"
                    >
                      <p className="font-bold text-indigo-600 dark:text-indigo-400 truncate mb-1">{source.title}</p>
                      <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate opacity-70">{source.uri}</p>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 dark:text-gray-500 opacity-50 space-y-4">
            <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            <p className="text-lg italic font-light">Search results will appear here...</p>
          </div>
        )}
      </div>
    </div>
  );
}

import React from 'react';
import { Source, ActiveView, UserTier } from '../types';

interface LeftSidebarProps {
  sources: Source[];
  onFileUpload: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onSelectSource: (source: Source) => void;
  onDeleteSource: (sourceId: string) => void;
  selectedSource: Source | null;
  activeView: ActiveView;
  setActiveView: (view: ActiveView) => void;
  userTier: UserTier;
  onUpgradeClick: () => void;
  theme: 'light' | 'dark';
  toggleTheme: () => void;
  isAuthenticated: boolean;
  onLoginClick: () => void;
  onLogout: () => void;
  searchCount: number;
  maxSearches: number;
}

const NavItem: React.FC<{
  icon: React.ReactElement;
  label: string;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
  isPremium?: boolean;
}> = ({ icon, label, isActive, onClick, disabled, isPremium = false }) => (
  <button
    onClick={onClick}
    disabled={disabled}
    className={`flex items-center w-full px-4 py-3 text-sm font-medium rounded-lg transition-colors duration-200 ${
      isActive
        ? 'bg-indigo-600 text-white'
        : 'text-gray-500 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 hover:text-gray-900 dark:hover:text-white'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span className="ml-3 flex-grow text-left">{label}</span>
    {isPremium && <span className="text-[10px] font-extrabold text-yellow-600 dark:text-yellow-400 bg-yellow-100 dark:bg-yellow-900/40 px-2 py-0.5 rounded-full border border-yellow-200 dark:border-yellow-700/50">PRO</span>}
  </button>
);

export default function LeftSidebar({
  sources,
  onFileUpload,
  onSelectSource,
  onDeleteSource,
  selectedSource,
  activeView,
  setActiveView,
  userTier,
  onUpgradeClick,
  theme,
  toggleTheme,
  isAuthenticated,
  onLoginClick,
  onLogout,
  searchCount,
  maxSearches,
}: LeftSidebarProps) {

  const handleSearchClick = () => {
    setActiveView('search');
  };

  const handleAddSourceClick = (event: React.MouseEvent<HTMLLabelElement>) => {
    if (!isAuthenticated) {
      event.preventDefault();
      onLoginClick();
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, source: Source) => {
    e.stopPropagation();
    if (window.confirm(`Are you sure you want to delete "${source.name}"?`)) {
        onDeleteSource(source.id);
    }
  };

  const searchPercentage = Math.min(100, (searchCount / maxSearches) * 100);

  return (
    <aside className="w-80 bg-white dark:bg-gray-800 p-4 flex flex-col h-full border-r border-gray-200 dark:border-gray-700 shadow-xl z-20">
      <div className="flex items-center mb-6">
        <svg className="w-8 h-8 text-indigo-500 dark:text-indigo-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" />
        </svg>
        <div className="ml-2">
          <h1 className="text-xl font-bold text-gray-900 dark:text-white">StudyLM</h1>
          <p className="text-[10px] text-gray-500 dark:text-gray-400 -mt-1 uppercase tracking-widest font-bold">Smart Revision</p>
        </div>
      </div>

      <div className="mb-4">
        <label
          htmlFor="file-upload"
          onClick={handleAddSourceClick}
          className="w-full text-center px-4 py-2 bg-indigo-600 text-white rounded-md cursor-pointer hover:bg-indigo-700 transition-all duration-200 block font-semibold shadow-md active:scale-95"
        >
          + Add Source
        </label>
        <input id="file-upload" type="file" className="hidden" onChange={onFileUpload} accept=".txt,.md" />
      </div>

      <div className="flex-grow overflow-y-auto pr-2 -mr-2 scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-gray-600">
        <h2 className="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3 px-2">Knowledge Base</h2>
        <ul className="space-y-1">
          {sources.map(source => (
            <li key={source.id} className="group relative flex items-center">
              <button
                onClick={() => onSelectSource(source)}
                className={`flex-grow text-left px-3 py-2.5 rounded-md text-sm transition-all duration-200 truncate ${
                  selectedSource?.id === source.id ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-300 font-bold border-l-4 border-indigo-500' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 border-l-4 border-transparent'
                }`}
              >
                {source.name}
              </button>
              {!source.id.startsWith('sample-') && (
                <button 
                  onClick={(e) => handleDeleteClick(e, source)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-full text-gray-400 hover:bg-red-500 hover:text-white opacity-0 group-hover:opacity-100 transition-all focus:opacity-100"
                  aria-label={`Delete ${source.name}`}
                >
                  <TrashIcon/>
                </button>
              )}
            </li>
