                          <svg className="w-4 h-4 mr-1" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"></path></svg>
                          Unlimited Search Active
                      </p>
                  )}
              </div>
            )}

            <div className="flex items-center justify-between gap-2">
                {isAuthenticated ? (
                  <button onClick={onLogout} className="flex-grow flex items-center justify-center text-sm text-gray-400 hover:text-red-500 font-bold transition-colors py-2 px-3 border border-transparent hover:border-red-100 dark:hover:border-red-900/30 rounded-lg">
                      <LogoutIcon />
