import { GoogleGenAI, Type } from "@google/genai";
import { RevisionPlan, Flashcard, QuizQuestion, AiSearchResult, GroundingSource, TrustedSource, ExamBoard, SearchMessage } from '../types';

if (!process.env.API_KEY) {
    // In a real app, you'd want to handle this more gracefully.
    // For this example, we'll throw an error if the key is missing.
    throw new Error("API_KEY environment variable not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const trustedSourceDomains: Record<TrustedSource, string> = {
    'Britannica': 'britannica.com',
    'Khan Academy': 'khanacademy.org',
    'Wikipedia': 'wikipedia.org',
};


export async function generateRevisionPlan(sourceText: string): Promise<RevisionPlan> {
    const model = "gemini-3-flash-preview";
    const prompt = `Based on the following learning material, create a structured revision plan. Break down the main topics and list key subtopics or concepts to review for each.

    Material:
    ---
    ${sourceText}
    ---

    Provide the output as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        topic: {
                            type: Type.STRING,
                            description: "The main topic or chapter to review."
                        },
                        subtopics: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING },
                            description: "A list of key subtopics, concepts, or terms under the main topic."
                        }
                    },
                    required: ["topic", "subtopics"]
                }
            }
        }
    });

    const text = response.text?.trim();
    if (!text) {
        throw new Error("Failed to generate revision plan: empty response from model.");
    }
    return JSON.parse(text);
}

export async function generateFlashcards(sourceText: string): Promise<Flashcard[]> {
    const model = "gemini-3-flash-preview";
    const prompt = `From the text provided, create a set of 10-15 flashcards. Each flashcard should have a clear term and a concise definition.

    Text:
    ---
    ${sourceText}
    ---

    Return the result as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        term: {
                            type: Type.STRING,
                            description: "The key term, concept, or question for the front of the flashcard."
                        },
                        definition: {
                            type: Type.STRING,
                            description: "The definition or answer for the back of the flashcard."
                        }
                    },
                    required: ["term", "definition"]
                }
            }
        }
    });

    const text = response.text?.trim();
    if (!text) {
        throw new Error("Failed to generate flashcards: empty response from model.");
    }
    return JSON.parse(text);
}

export async function generateQuiz(sourceText: string, questionCount: number): Promise<QuizQuestion[]> {
    const model = "gemini-3-flash-preview";
    const prompt = `Create a multiple-choice quiz with exactly ${questionCount} questions based on the provided material. For each question, provide 4 distinct options and clearly indicate the correct answer. The correct answer must be one of the options.

    Material:
    ---
    ${sourceText}
    ---

    Provide the output as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: {
                            type: Type.STRING,
                            description: "The quiz question."
                        },
                        options: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING },
                            description: "An array of 4 possible answers."
                        },
                        correctAnswer: {
                            type: Type.STRING,
                            description: "The correct answer, which must match one of the items in the 'options' array."
                        }
                    },
                    required: ["question", "options", "correctAnswer"]
                }
            }
        }
    });

    const text = response.text?.trim();
    if (!text) {
        throw new Error("Failed to generate quiz: empty response from model.");
    }
    return JSON.parse(text);
}

export async function answerQuestionBasedOnSource(sourceText: string, question: string) {
    const model = "gemini-3-flash-preview";
    const prompt = `You are a helpful study assistant. Using the provided source material, answer the user's question. If the answer isn't in the material, say so. Keep your answers concise and directly related to the source.

    Source Material:
    ---
    ${sourceText}
    ---

    User's Question: "${question}"`;

    const response = await ai.models.generateContentStream({
        model,
        contents: prompt,
    });

    return response;
}

export async function searchWithAi(history: SearchMessage[], trustedSources: TrustedSource[], examBoards: ExamBoard[]): Promise<AiSearchResult> {
    const model = "gemini-3-flash-preview";

    const lastUserMessage = history[history.length - 1];

    let fullQuery = `Provide a concise and informative answer to the following query, based on a web search: "${lastUserMessage.text}"`;

    if (trustedSources.length > 0) {
        const siteFilters = trustedSources.map(source => `site:${trustedSourceDomains[source]}`).join(' OR ');
        fullQuery += ` Prioritize information from these sources: ${siteFilters}.`;
    }

    if (examBoards.length > 0) {
        const boardFilters = examBoards.join(', ');
        fullQuery += ` Tailor the results to these specific UK exam boards: ${boardFilters}. Focus on revision material relevant to them.`;
    }

    const contents = history.map(msg => ({
        role: msg.sender === 'user' ? 'user' : 'model',
        parts: [{ text: msg === lastUserMessage ? fullQuery : msg.text }]
    }));

    const response = await ai.models.generateContent({
        model,
        contents,
        config: {
            tools: [{googleSearch: {}}],
        },
    });

    const summary = response.text || "No summary available.";

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: GroundingSource[] = groundingChunks
      .map(chunk => chunk.web)
      .filter(web => web && web.uri && web.title)
      .map(web => ({
        uri: web.uri!,
        title: web.title!,
      }));

    return { summary, sources };
}

import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, SearchMessage, ExamBoard, SearchStatus } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';

const MAX_FREE_SEARCHES = 15;

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchHistory, setSearchHistory] = useState<SearchMessage[]>([]);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);

  const [searchStatus, setSearchStatus] = useState<SearchStatus>(() => {
    const saved = localStorage.getItem('search-status');
    const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
    if (saved) {
      const parsed = JSON.parse(saved) as SearchStatus;
      if (parsed.lastDate === today) return parsed;
    }
    return { count: 0, lastDate: today };
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  useEffect(() => {
    localStorage.setItem('search-status', JSON.stringify(searchStatus));
  }, [searchStatus]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleDeleteSource = (sourceId: string) => {
    if (selectedSource?.id === sourceId) {
      setSelectedSource(sampleSources[0] || null);
      setActiveView('source');
    }
    setSources(prevSources => prevSources.filter(source => source.id !== sourceId));
  };


  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    if (view !== 'search') {
      setSearchHistory([]);
    }
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    const today = new Date().toLocaleDateString('en-CA');

    if (userTier === 'free') {
      if (searchStatus.lastDate === today && searchStatus.count >= MAX_FREE_SEARCHES) {
        setShowTierModal(true);
        return;
      }
    }

    const userMessage: SearchMessage = { sender: 'user', text: query };
    const currentHistory = [...searchHistory, userMessage];
    setSearchHistory(currentHistory);
    setIsLoading(true);
    setLoadingMessage('Searching with Gemini...');
    try {
      const result = await searchWithAi(currentHistory, trustedSources, examBoards);
      const aiMessage: SearchMessage = { sender: 'ai', text: result.summary, sources: result.sources };
      setSearchHistory(prev => [...prev, aiMessage]);

      if (userTier === 'free') {
        setSearchStatus(prev => ({
          count: prev.lastDate === today ? prev.count + 1 : 1,
          lastDate: today
        }));
      }
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      const errorMessage: SearchMessage = { sender: 'ai', text: "Sorry, I couldn't complete the search. Please try again."};
      setSearchHistory(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [userTier, searchStatus, searchHistory]);

  const renderMainContent = () => {
    if (isLoading && activeView !== 'search') {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchHistory={searchHistory} isLoading={isLoading} userTier={userTier} searchCount={searchStatus.count} maxSearches={MAX_FREE_SEARCHES} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} /> : null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans">
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        onDeleteSource={handleDeleteSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        toggleTheme={toggleTheme}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
        searchCount={searchStatus.count}
        maxSearches={MAX_FREE_SEARCHES}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} />
        </div>
      </main>
    </div>
  );
}

