import React from 'react';

const MarkdownRenderer = ({ content }: { content: string }) => {
    const elements: React.ReactNode[] = [];
    const lines = content.split('\n');
    let listItems: string[] = [];

    const parseInline = (text: string) => {
        const parts = text.split(/(\*\*.*?\*\*|\*.*?\*)/g);
        return parts.map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={i}>{part.slice(2, -2)}</strong>;
            }
            if (part.startsWith('*') && part.endsWith('*')) {
                return <em key={i}>{part.slice(1, -1)}</em>;
            }
            return part;
        }).filter(part => part !== '');
    };

    const flushList = (key: string) => {
        if (listItems.length > 0) {
            elements.push(
                <ul key={key} className="list-disc list-outside pl-6 space-y-1">
                    {listItems.map((item, i) => <li key={i}>{parseInline(item)}</li>)}
                </ul>
            );
            listItems = [];
        }
    };

    lines.forEach((line, index) => {
        if (line.startsWith('### ')) {
            flushList(`ul-${index}-pre`);
            elements.push(<h3 key={index} className="text-xl font-bold mt-4 mb-2">{parseInline(line.substring(4))}</h3>);
        } else if (line.startsWith('## ')) {
            flushList(`ul-${index}-pre`);
            elements.push(<h2 key={index} className="text-2xl font-bold mt-5 mb-2">{parseInline(line.substring(3))}</h2>);
        } else if (line.startsWith('# ')) {
            flushList(`ul-${index}-pre`);
            elements.push(<h1 key={index} className="text-3xl font-bold mt-6 mb-3">{parseInline(line.substring(2))}</h1>);
        } else if (line.match(/^\s*\*\s/)) {
            listItems.push(line.replace(/^\s*\*\s/, ''));
        } else if (line.trim() === '') {
            flushList(`ul-${index}-pre`);
        } else {
            flushList(`ul-${index}-pre`);
            elements.push(<p key={index} className="my-2">{parseInline(line)}</p>);
        }
    });

    flushList(`ul-final`);

    return <>{elements}</>;
};

