export default function ChatPanel({ selectedSource, isAuthenticated }: ChatPanelProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(false);
  const [attachedImage, setAttachedImage] = useState<{ data: string, mime: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  useEffect(() => {
    if (selectedSource) {
      setMessages([
        { sender: 'ai', text: `StudyLM Pro is ready. Analyzing "${selectedSource.name}". How can I help?` }
      ]);
    } else {
       setMessages([
        { sender: 'ai', text: isAuthenticated ? 'Select a source or upload an image to start a deep study session.' : 'Select a sample source to explore StudyLM Pro.' }
      ]);
    }
  }, [selectedSource, isAuthenticated]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setAttachedImage({
          data: ev.target?.result as string,
          mime: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !attachedImage) || isLoading) return;

    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: input || (attachedImage ? "Analyze this image." : ""),
        imageData: attachedImage?.data,
        mimeType: attachedImage?.mime,
        isThinking: useThinking
    };

    const newHistory = [...messages, userMessage];
    setMessages(newHistory);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const stream = await askGeminiPro(newHistory, useThinking, selectedSource?.content);
      let aiResponse = '';
      setMessages(prev => [...prev, { sender: 'ai', text: '', isThinking: useThinking }]);

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        aiResponse += c.text;
        setMessages(prev => {
          const updated = [...prev];
          updated[updated.length - 1].text = aiResponse;
          return updated;
        });
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { sender: 'ai', text: "Gemini encountered an issue. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full p-4 relative">
      <div className="flex items-center justify-between mb-4 border-b border-gray-200 dark:border-gray-700 pb-2">
        <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center">
            <svg className="w-5 h-5 mr-2 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M2 5a2 2 0 012-2h7a2 2 0 012 2v4a2 2 0 01-2 2H9l-3 3v-3H4a2 2 0 01-2-2V5z"></path></svg>
            StudyLM Pro
        </h2>
        <button 
            onClick={() => setUseThinking(!useThinking)}
            className={`flex items-center space-x-2 px-3 py-1 rounded-full text-xs font-bold transition-all duration-300 border ${
                useThinking 
                ? 'bg-indigo-600 text-white border-indigo-400 shadow-md animate-pulse' 
                : 'bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 border-transparent hover:border-gray-300 dark:hover:border-gray-600'
            }`}
            title="Enable Gemini Thinking Mode for complex reasoning"
        >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>
            <span>DEEP THINK</span>
        </button>
      </div>

      <div className="flex-grow overflow-y-auto mb-4 pr-2 space-y-4">
        {messages.map((msg, index) => (
          <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] px-4 py-3 rounded-2xl shadow-sm ${
                msg.sender === 'user' 
                ? 'bg-indigo-600 text-white' 
                : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200'
            }`}>
              {msg.imageData && (
                  <div className="mb-2 rounded-lg overflow-hidden border border-white/20">
                      <img src={msg.imageData} alt="Uploaded for analysis" className="w-full h-auto max-h-48 object-cover" />
                  </div>
              )}
              {msg.isThinking && msg.sender === 'ai' && !msg.text && (
                  <div className="flex items-center text-xs text-indigo-500 dark:text-indigo-400 font-bold mb-1">
                      <svg className="w-3 h-3 mr-1 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      Thinking deeply...
                  </div>
              )}
              <div className="prose prose-sm dark:prose-invert">
                <MarkdownRenderer content={msg.text} />
              </div>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length-1].sender === 'user' && (
            <div className="flex justify-start">
                <div className="bg-gray-100 dark:bg-gray-700 px-4 py-2 rounded-2xl shadow-sm">
                    <div className="flex items-center space-x-2">
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                    </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="relative">
          {attachedImage && (
              <div className="absolute bottom-full left-0 mb-2 p-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-xl flex items-center group">
                  <img src={attachedImage.data} className="w-12 h-12 rounded object-cover" />
                  <button 
                    onClick={() => setAttachedImage(null)}
                    className="ml-2 p-1 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded"
                  >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
              </div>
          )}
          <form onSubmit={handleSendMessage} className="flex items-center bg-gray-100 dark:bg-gray-700 rounded-2xl p-1 shadow-inner border border-transparent focus-within:border-indigo-500 transition-all">
            <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" className="hidden" />
            <button 
                type="button" 
                onClick={() => fileInputRef.current?.click()}
                className="p-3 text-gray-500 hover:text-indigo-500 dark:text-gray-400 dark:hover:text-indigo-300 transition-colors"
                title="Upload image for AI analysis"
            >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            </button>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isLoading ? "Gemini is thinking..." : "Ask StudyLM anything..."}
              disabled={isLoading}
              className="flex-grow bg-transparent text-gray-900 dark:text-white p-3 focus:outline-none text-sm placeholder:text-gray-400"
            />
            <button type="submit" disabled={(!input.trim() && !attachedImage) || isLoading} className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 disabled:bg-gray-400 dark:disabled:bg-gray-600 shadow-lg active:scale-95 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
            </button>
          </form>
      </div>
    </div>
  );
}

{
  "name": "StudyLM",
  "description": "An intelligent study partner similar to NotebookLM. Upload your learning materials to generate revision plans, interactive flashcards, and AI-powered quizzes to supercharge your learning.",
  "requestFramePermissions": ["camera"]
}

import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, SearchMessage, ExamBoard, SearchStatus } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';
import UpgradeToProPanel from './components/UpgradeToProPanel';

const MAX_FREE_SEARCHES = 15;

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchHistory, setSearchHistory] = useState<SearchMessage[]>([]);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);

  const [searchStatus, setSearchStatus] = useState<SearchStatus>(() => {
    const saved = localStorage.getItem('search-status');
    const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
    if (saved) {
      const parsed = JSON.parse(saved) as SearchStatus;
      if (parsed.lastDate === today) return parsed;
    }
    return { count: 0, lastDate: today };
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  useEffect(() => {
    localStorage.setItem('search-status', JSON.stringify(searchStatus));
  }, [searchStatus]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleDeleteSource = (sourceId: string) => {
    if (selectedSource?.id === sourceId) {
      setSelectedSource(sampleSources[0] || null);
      setActiveView('source');
    }
    setSources(prevSources => prevSources.filter(source => source.id !== sourceId));
  };


  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    if (view !== 'search') {
      setSearchHistory([]);
    }
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    const today = new Date().toLocaleDateString('en-CA');

    if (userTier === 'free') {
      if (searchStatus.lastDate === today && searchStatus.count >= MAX_FREE_SEARCHES) {
        setShowTierModal(true);
        return;
      }
    }

    const userMessage: SearchMessage = { sender: 'user', text: query };
    const currentHistory = [...searchHistory, userMessage];
    setSearchHistory(currentHistory);
    setIsLoading(true);
    setLoadingMessage('Searching with Gemini...');
    try {
      const result = await searchWithAi(currentHistory, trustedSources, examBoards);
      const aiMessage: SearchMessage = { sender: 'ai', text: result.summary, sources: result.sources };
      setSearchHistory(prev => [...prev, aiMessage]);

      if (userTier === 'free') {
        setSearchStatus(prev => ({
          count: prev.lastDate === today ? prev.count + 1 : 1,
          lastDate: today
        }));
      }
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      const errorMessage: SearchMessage = { sender: 'ai', text: "Sorry, I couldn't complete the search. Please try again."};
      setSearchHistory(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [userTier, searchStatus, searchHistory]);

  const renderMainContent = () => {
    if (isLoading && activeView !== 'search') {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchHistory={searchHistory} isLoading={isLoading} userTier={userTier} searchCount={searchStatus.count} maxSearches={MAX_FREE_SEARCHES} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} /> : null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans">
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        onDeleteSource={handleDeleteSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        toggleTheme={toggleTheme}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
        searchCount={searchStatus.count}
        maxSearches={MAX_FREE_SEARCHES}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          {userTier === 'premium' ? (
            <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} />
          ) : (
            <UpgradeToProPanel onUpgradeClick={() => setShowTierModal(true)} />
          )}
        </div>
      </main>
    </div>
  );
}

import React from 'react';

